private static PixelBuffer[] ProcessMultiImpl(PixelBuffer?[] inputs, IReadOnlyDictionary<string, object> parameters, PixelGraphContext context)
{
    var seed = GetInt(parameters, "seed", context.Seed);
    var frameCount = GetInt(parameters, "frameCount", 8);
    var playMode = GetChoice(parameters, "playMode", "loop");
    var rawFrame = GetFloat(parameters, "frame", 0f);

    var size = context.TileSize;
    var image = new PixelBuffer(size, size);
    var mask = new PixelBuffer(size, size);

    // Apply play mode to derive effective normalized time [0, 1)
    var t = playMode switch
    {
        "pingPong" => 1f - MathF.Abs(rawFrame * 2f - 1f),
        "singleShot" => Math.Clamp(rawFrame, 0f, 1f),
        _ => rawFrame % 1f  // loop
    };

    // Map t to a discrete frame index
    var frameIdx = (int)(t * frameCount);
    if (frameIdx >= frameCount) frameIdx = frameCount - 1;
    var framePhase = frameIdx / (float)Math.Max(1, frameCount);

    var halfSize = size * 0.5f;
    var invSize = 1f / size;

    image.ParallelForEachPixel((x, y) =>
    {
        // Normalized coordinates centered at (0.5, 0.5)
        var u = (x + 0.5f) * invSize;
        var v = (y + 0.5f) * invSize;
        var cx = u - 0.5f;
        var cy = v - 0.5f;

        var dist = MathF.Sqrt(cx * cx + cy * cy);
        var angle = MathF.Atan2(cy, cx);

        // Per-pixel frequency based on distance and angle
        var radialFreq = 2f + MathF.Sin(dist * 6f + seed * 0.01f) * 1.5f;
        var angularFreq = 1f + MathF.Cos(angle * 3f + seed * 0.02f) * 0.5f;

        // Noise-derived per-pixel offset
        var noiseOffset = HashToUnit((int)(x * 7 + y * 13), (int)(x * 11 + y * 5), seed);

        // Primary oscillation: concentric rings that move
        var ringPhase = dist * radialFreq * MathF.PI * 2f;
        var spinPhase = angle * angularFreq;
        var framePhaseOffset = framePhase * MathF.PI * 2f;

        var value = MathF.Sin(ringPhase + spinPhase + framePhaseOffset + noiseOffset * MathF.PI);
        value = value * 0.5f + 0.5f; // Normalize to [0, 1]

        // Secondary layer: traveling gradient bands
        var bandValue = MathF.Sin((u + v * 0.7f) * 4f * MathF.PI + framePhaseOffset * 0.5f + noiseOffset);
        bandValue = bandValue * 0.5f + 0.5f;

        // Blend primary and secondary layers
        var blendWeight = 0.6f + 0.4f * MathF.Sin(dist * MathF.PI * 2f + framePhase);
        var finalValue = Lerp(bandValue, value, blendWeight);
        finalValue = Math.Clamp(finalValue, 0f, 1f);

        // Color: hue shift based on angle and frame
        var hueShift = angle / MathF.PI * 0.5f + 0.5f + framePhase;
        var r = finalValue * (0.6f + 0.4f * MathF.Sin(hueShift * MathF.PI * 2f));
        var g = finalValue * (0.6f + 0.4f * MathF.Sin((hueShift + 0.33f) * MathF.PI * 2f));
        var b = finalValue * (0.6f + 0.4f * MathF.Sin((hueShift + 0.67f) * MathF.PI * 2f));

        image.SetPixel(x, y,
            Math.Clamp(r, 0f, 1f),
            Math.Clamp(g, 0f, 1f),
            Math.Clamp(b, 0f, 1f),
            1f);

        // Mask: grayscale oscillation for external modulation use
        mask.SetPixel(x, y, finalValue, finalValue, finalValue, 1f);
    });

    return [image, mask];
    }
}
